#include <iostream>
#include <memory>
#include <utility>

int main() {
    int value{};
    if (!(std::cin >> value)) return 1;
    auto source = std::make_unique<int>(value);
    std::unique_ptr<int> owner = std::move(source);
    std::cout << (source ? "owned" : "empty") << ' ' << *owner << '\n';
}
